import { useState, useEffect, useRef } from "react";
import { useWeddingData } from "./useWeddingData";
import { storage } from "./firebase";
import { ref, uploadBytesResumable, getDownloadURL } from "firebase/storage";

const PHOTOS_COUPLE = [
  { id:"c1", src:"data:image/jpeg;base64,", label:"Notre complicité", author:"Id'Art" },
  { id:"c2", src:"data:image/jpeg;base64,", label:"Un baiser tendre", author:"Id'Art" },
  { id:"c3", src:"data:image/jpeg;base64,", label:"Notre petite famille", author:"Id'Art" },
  { id:"c4", src:"data:image/jpeg;base64,", label:"Côte à côte", author:"Id'Art" },
  { id:"c5", src:"data:image/jpeg;base64,", label:"Ensemble pour toujours", author:"Id'Art" },
];

const NAV = [
  { id:"accueil", icon:"💍", label:"Accueil" },
  { id:"programme", icon:"📋", label:"Programme" },
  { id:"infos", icon:"📍", label:"Infos" },
  { id:"rsvp", icon:"✉️", label:"RSVP" },
  { id:"photos", icon:"📸", label:"Photos" },
  { id:"or", icon:"💌", label:"Livre d'or" },
  { id:"menu", icon:"🍽️", label:"Menu" },
  { id:"table", icon:"🪑", label:"Tables" },
];

const S = `
  @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&family=Nunito:wght@300;400;600;700&display=swap');
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { background: #1a0a00; font-family: 'Nunito', sans-serif; color: #2a1a0a; }
  .app { max-width: 430px; margin: 0 auto; min-height: 100vh; background: #fdf8f0; position: relative; padding-bottom: 80px; }
  .hero { position: relative; height: 520px; overflow: hidden; }
  .hero img { width: 100%; height: 100%; object-fit: cover; object-position: top; }
  .hero-ov { position: absolute; inset: 0; background: linear-gradient(to bottom, rgba(0,0,0,0.1) 0%, rgba(20,8,0,0.7) 70%, rgba(20,8,0,0.95) 100%); }
  .hero-c { position: absolute; bottom: 0; left: 0; right: 0; padding: 24px; text-align: center; }
  .hero-sub { font-size: 11px; letter-spacing: 4px; text-transform: uppercase; color: #d4a96a; margin-bottom: 8px; }
  .hero-names { font-family: 'Playfair Display', serif; font-size: 46px; color: #fdf8f0; line-height: 1.05; }
  .hero-and { font-style: italic; color: #d4a96a; display: block; font-size: 28px; margin: 4px 0; }
  .hero-date { font-size: 13px; letter-spacing: 2px; color: #d4a96a; margin-top: 12px; }
  .cd { background: linear-gradient(135deg, #8B4513, #c8860a, #8B4513); margin: 0 16px; border-radius: 16px; padding: 18px 20px; display: flex; justify-content: space-around; box-shadow: 0 8px 32px rgba(139,69,19,0.4); margin-top: -20px; position: relative; z-index: 2; }
  .cd-u { text-align: center; }
  .cd-n { font-family: 'Playfair Display', serif; font-size: 34px; color: #fdf8f0; line-height: 1; }
  .cd-l { font-size: 9px; letter-spacing: 2px; text-transform: uppercase; color: #f5d9a8; margin-top: 4px; }
  .cd-s { font-family: 'Playfair Display', serif; font-size: 24px; color: #f5d9a8; align-self: center; margin-bottom: 14px; }
  .tabs { display: flex; overflow-x: auto; gap: 0; background: #f5ece0; padding: 6px; margin: 16px; border-radius: 14px; scrollbar-width: none; }
  .tabs::-webkit-scrollbar { display: none; }
  .tab { flex: 0 0 auto; padding: 8px 12px; font-size: 11px; letter-spacing: 1px; text-transform: uppercase; border: none; background: transparent; color: #8B6035; border-radius: 10px; cursor: pointer; transition: all 0.2s; white-space: nowrap; font-family: 'Nunito', sans-serif; font-weight: 600; }
  .tab.active { background: #8B4513; color: #fdf8f0; box-shadow: 0 2px 8px rgba(139,69,19,0.3); }
  .sec { padding: 0 16px; animation: fu 0.3s ease; }
  @keyframes fu { from { opacity:0; transform: translateY(10px); } to { opacity:1; transform:translateY(0); } }
  .st { font-family: 'Playfair Display', serif; font-size: 30px; color: #2a1a0a; margin-bottom: 2px; }
  .ss { font-size: 11px; letter-spacing: 2px; text-transform: uppercase; color: #8B6035; margin-bottom: 20px; }
  .card { background: white; border-radius: 16px; padding: 18px; margin-bottom: 14px; box-shadow: 0 2px 12px rgba(139,69,19,0.08); }
  .btn-main { width: 100%; padding: 14px; background: linear-gradient(135deg, #8B4513, #c8860a); color: #fdf8f0; border: none; border-radius: 14px; font-size: 13px; letter-spacing: 1px; text-transform: uppercase; cursor: pointer; font-family: 'Nunito', sans-serif; font-weight: 700; transition: opacity 0.2s; }
  .btn-main:hover { opacity: 0.9; }
  .btn-main:disabled { opacity: 0.5; cursor: not-allowed; }
  .inp { width: 100%; border: 1.5px solid #e8dcd0; border-radius: 10px; padding: 11px 14px; font-size: 14px; font-family: 'Nunito', sans-serif; color: #2a1a0a; background: #fdf8f0; outline: none; transition: border-color 0.2s; }
  .inp:focus { border-color: #c8860a; }
  .prog-item { display: flex; gap: 14px; margin-bottom: 12px; background: white; border-radius: 14px; padding: 14px; box-shadow: 0 2px 10px rgba(139,69,19,0.08); border-left: 3px solid #c8860a; }
  .info-card { border-radius: 16px; padding: 16px; margin-bottom: 12px; box-shadow: 0 2px 10px rgba(139,69,19,0.08); }
  .menu-item { background: white; border-radius: 12px; padding: 14px; margin-bottom: 8px; display: flex; align-items: center; gap: 12px; box-shadow: 0 1px 8px rgba(139,69,19,0.07); cursor: pointer; border: 2px solid transparent; transition: all 0.2s; }
  .menu-item.sel { border-color: #c8860a; background: #fdf3e8; }
  .menu-check { width: 22px; height: 22px; border-radius: 50%; border: 2px solid #d0c4b8; display: flex; align-items: center; justify-content: center; transition: all 0.2s; flex-shrink: 0; margin-left: auto; }
  .menu-item.sel .menu-check { background: #c8860a; border-color: #c8860a; color: white; font-size: 12px; }
  .rsvp-stats { display: flex; gap: 10px; margin-bottom: 18px; }
  .stat-box { flex:1; text-align:center; padding: 14px 8px; border-radius: 14px; }
  .stat-num { font-family: 'Playfair Display', serif; font-size: 30px; }
  .guest-row { display: flex; align-items: center; gap: 10px; padding: 10px 0; border-bottom: 1px solid #f5ece0; }
  .guest-row:last-child { border-bottom: none; }
  .guest-av { width: 36px; height: 36px; border-radius: 50%; background: linear-gradient(135deg, #c8860a, #8B4513); display: flex; align-items: center; justify-content: center; font-family: 'Playfair Display', serif; font-size: 15px; color: white; flex-shrink: 0; }
  .bdg { padding: 3px 10px; border-radius: 20px; font-size: 10px; font-weight: 700; }
  .bdg-y { background: #e6f4ea; color: #2d8a4e; }
  .bdg-n { background: #fde8e8; color: #c0392b; }
  .photo-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; margin-bottom: 14px; }
  .photo-card { border-radius: 14px; overflow: hidden; box-shadow: 0 2px 12px rgba(139,69,19,0.12); }
  .photo-card img { width: 100%; height: 130px; object-fit: cover; display: block; }
  .photo-info { padding: 8px 10px; background: white; }
  .upload-zone { border: 2px dashed #d4b896; border-radius: 16px; padding: 28px 20px; text-align: center; cursor: pointer; transition: all 0.2s; background: #fdf8f0; margin-bottom: 14px; }
  .upload-zone:hover, .upload-zone.drag { border-color: #c8860a; background: #fdf3e8; }
  .upload-zone input { display: none; }
  .progress-bar { height: 6px; background: #f5ece0; border-radius: 3px; overflow: hidden; margin-top: 10px; }
  .progress-fill { height: 100%; background: linear-gradient(90deg, #8B4513, #c8860a); border-radius: 3px; transition: width 0.3s; }
  .modal-overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.55); z-index: 200; display: flex; align-items: flex-end; justify-content: center; padding: 0; }
  .modal-box { background: white; border-radius: 24px 24px 0 0; padding: 28px 24px 36px; width: 100%; max-width: 430px; animation: slideup 0.3s ease; }
  @keyframes slideup { from { transform: translateY(100%); } to { transform: translateY(0); } }
  .msg-card { background: white; border-radius: 14px; padding: 14px; margin-bottom: 10px; box-shadow: 0 2px 10px rgba(139,69,19,0.07); border-left: 3px solid #c8860a; }
  .invite-card { background: linear-gradient(160deg, #2a1a0a 0%, #5a3010 100%); margin: 16px; border-radius: 20px; padding: 24px; text-align: center; color: #fdf8f0; box-shadow: 0 8px 32px rgba(139,69,19,0.4); }
  .date-box { flex: 1; background: rgba(255,255,255,0.1); border-radius: 12px; padding: 12px; }
  .date-day { font-family: 'Playfair Display', serif; font-size: 28px; color: #fdf8f0; line-height: 1; }
  .date-month { font-size: 11px; letter-spacing: 2px; color: #d4a96a; text-transform: uppercase; }
  .date-event { font-size: 11px; color: #e8c89a; margin-top: 4px; }
  .slider { display: flex; overflow-x: auto; gap: 12px; padding: 0 16px 8px; scrollbar-width: none; }
  .slider::-webkit-scrollbar { display: none; }
  .slide { flex: 0 0 220px; border-radius: 16px; overflow: hidden; box-shadow: 0 4px 20px rgba(139,69,19,0.2); }
  .slide img { width: 100%; height: 270px; object-fit: cover; object-position: top; display: block; }
  .slide-info { background: white; padding: 10px 12px; }
  .bnav { position: fixed; bottom: 0; left: 50%; transform: translateX(-50%); width: 100%; max-width: 430px; background: white; border-top: 1px solid #f0e4d4; display: flex; z-index: 100; box-shadow: 0 -4px 20px rgba(139,69,19,0.1); }
  .nb { flex: 1; padding: 9px 2px 7px; border: none; background: transparent; cursor: pointer; display: flex; flex-direction: column; align-items: center; gap: 2px; font-family: 'Nunito', sans-serif; }
  .nb-icon { font-size: 18px; transition: transform 0.2s; }
  .nb.active .nb-icon { transform: translateY(-2px); }
  .nb-label { font-size: 8px; letter-spacing: 0.5px; text-transform: uppercase; color: #b09070; font-weight: 600; }
  .nb.active .nb-label { color: #8B4513; }
  .loading { display: flex; flex-direction: column; align-items: center; justify-content: center; height: 100vh; background: #fdf8f0; gap: 16px; }
  .spinner { width: 40px; height: 40px; border: 3px solid #f5ece0; border-top-color: #c8860a; border-radius: 50%; animation: spin 0.8s linear infinite; }
  @keyframes spin { to { transform: rotate(360deg); } }
  .toast { position: fixed; bottom: 90px; left: 50%; transform: translateX(-50%); background: linear-gradient(135deg,#8B4513,#c8860a); color: #fdf8f0; padding: 12px 24px; border-radius: 30px; font-size: 13px; font-weight: 700; box-shadow: 0 4px 20px rgba(139,69,19,0.4); z-index: 300; white-space: nowrap; animation: toastin 0.3s ease; }
  @keyframes toastin { from { opacity:0; transform: translateX(-50%) translateY(10px); } to { opacity:1; transform: translateX(-50%) translateY(0); } }
`;

export default function GuestApp() {
  const { data, loading, saveSection } = useWeddingData();
  const [tab, setTab] = useState("accueil");
  const [countdown, setCountdown] = useState({});
  const [toast, setToast] = useState(null);
  const [rsvpStep, setRsvpStep] = useState("form");
  const [rsvpPrenom, setRsvpPrenom] = useState("");
  const [rsvpNom, setRsvpNom] = useState("");
  const [rsvpChoice, setRsvpChoice] = useState(null);
  const [selectedMeal, setSelectedMeal] = useState(null);
  const [newMsg, setNewMsg] = useState("");
  const [newMsgPrenom, setNewMsgPrenom] = useState("");
  const [newMsgNom, setNewMsgNom] = useState("");
  const [uploadFile, setUploadFile] = useState(null);
  const [uploaderName, setUploaderName] = useState("");
  const [uploading, setUploading] = useState(false);
  const [uploadProgress, setUploadProgress] = useState(0);
  const [drag, setDrag] = useState(false);
  const fileRef = useRef();

  const showToast = (msg) => { setToast(msg); setTimeout(() => setToast(null), 3000); };

  useEffect(() => {
    if (!data) return;
    const tick = () => {
      const now = new Date();
      const diff = new Date(data.couple.date1 + "T14:00:00") - now;
      if (diff <= 0) { setCountdown({days:0,hours:0,mins:0,secs:0}); return; }
      setCountdown({ days:Math.floor(diff/86400000), hours:Math.floor((diff%86400000)/3600000), mins:Math.floor((diff%3600000)/60000), secs:Math.floor((diff%60000)/1000) });
    };
    tick(); const iv = setInterval(tick,1000); return ()=>clearInterval(iv);
  }, [data]);

  if (loading) return (<><style>{S}</style><div className="loading"><div className="spinner"/><div style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:"#8B4513"}}>Chargement...</div></div></>);

  const { couple, programme, infos, tables, menus, messages } = data;
  const photos = data.photos || [];
  const rsvps = data.rsvps || [];

  const submitRsvp = async () => {
    if (!rsvpPrenom.trim() || !rsvpNom.trim()) return;
    const entry = { id:Date.now().toString(), prenom:rsvpPrenom.trim(), nom:rsvpNom.trim(), fullName:`${rsvpPrenom.trim()} ${rsvpNom.trim()}`, present:rsvpChoice==="yes", time:new Date().toLocaleString("fr-FR",{day:"2-digit",month:"2-digit",hour:"2-digit",minute:"2-digit"}) };
    await saveSection("rsvps", [...rsvps, entry]);
    setRsvpStep("done");
    showToast(rsvpChoice==="yes" ? "🎉 Présence confirmée !" : "💕 Message bien reçu");
  };

  const handleFile = (file) => { if (file && file.type.startsWith("image/")) setUploadFile(file); };

  const confirmUpload = async () => {
    if (!uploadFile || !uploaderName.trim()) return;
    setUploading(true); setUploadProgress(0);
    try {
      const ext = uploadFile.name.split(".").pop();
      const path = `photos/${Date.now()}_${Math.random().toString(36).slice(2)}.${ext}`;
      const task = uploadBytesResumable(ref(storage, path), uploadFile);
      task.on("state_changed",
        s => setUploadProgress(Math.round((s.bytesTransferred/s.totalBytes)*100)),
        err => { console.error(err); setUploading(false); showToast("❌ Erreur d'envoi"); },
        async () => {
          const url = await getDownloadURL(task.snapshot.ref);
          const photo = { id:Date.now().toString(), url, label:uploadFile.name.replace(/\.[^.]+$/,""), author:uploaderName.trim(), time:new Date().toLocaleString("fr-FR",{day:"2-digit",month:"2-digit",hour:"2-digit",minute:"2-digit"}) };
          await saveSection("photos", [...photos, photo]);
          setUploading(false); setUploadFile(null); setUploaderName(""); setUploadProgress(0);
          showToast("📸 Photo partagée !");
        }
      );
    } catch(e) { console.error(e); setUploading(false); }
  };

  const sendMessage = async () => {
    if (!newMsg.trim() || !newMsgPrenom.trim() || !newMsgNom.trim()) return;
    const msg = { id:Date.now().toString(), name:`${newMsgPrenom.trim()} ${newMsgNom.trim()}`, msg:newMsg.trim(), time:new Date().toLocaleTimeString("fr-FR",{hour:"2-digit",minute:"2-digit"}), approved:false };
    await saveSection("messages", [...messages, msg]);
    setNewMsg(""); setNewMsgPrenom(""); setNewMsgNom("");
    showToast("💌 Message envoyé — en attente d'approbation");
  };

  const grouped = programme.reduce((a,p) => { if(!a[p.date]) a[p.date]=[]; a[p.date].push(p); return a; }, {});
  const presentCount = rsvps.filter(r=>r.present).length;
  const absentCount = rsvps.filter(r=>!r.present).length;

  return (
    <>
      <style>{S}</style>

      {/* MODAL UPLOAD */}
      {uploadFile && (
        <div className="modal-overlay" onClick={e=>{ if(e.target.className==="modal-overlay"){ setUploadFile(null); setUploaderName(""); }}}>
          <div className="modal-box">
            <div style={{fontSize:32,textAlign:"center",marginBottom:10}}>📸</div>
            <div style={{fontFamily:"'Playfair Display',serif",fontSize:22,color:"#2a1a0a",textAlign:"center",marginBottom:4}}>Partager cette photo</div>
            <div style={{fontSize:12,color:"#8B6035",textAlign:"center",marginBottom:20}}>1 photo sélectionnée</div>
            <div style={{marginBottom:14}}>
              <label style={{fontSize:10,letterSpacing:1.5,textTransform:"uppercase",color:"#8B6035",fontWeight:700,display:"block",marginBottom:6}}>Votre prénom &amp; nom</label>
              <input className="inp" placeholder="Ex : Marie Nzamba" value={uploaderName} onChange={e=>setUploaderName(e.target.value)} autoFocus />
            </div>
            {uploading && (
              <div style={{marginBottom:14}}>
                <div style={{fontSize:12,color:"#8B6035",marginBottom:6,textAlign:"center"}}>Envoi en cours... {uploadProgress}%</div>
                <div className="progress-bar"><div className="progress-fill" style={{width:`${uploadProgress}%`}}/></div>
              </div>
            )}
            <div style={{display:"flex",gap:10,marginTop:6}}>
              <button onClick={()=>{setUploadFile(null);setUploaderName("");}} style={{flex:1,padding:"13px",borderRadius:12,border:"1.5px solid #e8dcd0",background:"white",color:"#8B6035",cursor:"pointer",fontFamily:"'Nunito',sans-serif",fontWeight:700,fontSize:13}}>Annuler</button>
              <button className="btn-main" style={{flex:2}} onClick={confirmUpload} disabled={uploading||!uploaderName.trim()}>
                {uploading ? `${uploadProgress}%...` : "📤 Envoyer"}
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="app">
        {/* HERO */}
        <div className="hero" style={{background:"linear-gradient(160deg,#2a1a0a,#8B4513)"}}>
          <img src="data:image/jpeg;base64," alt="Prudence et Praxèd" onError={e=>e.target.style.display="none"} />
          <div className="hero-ov"/>
          <div className="hero-c">
            <div className="hero-sub">Célébrons l'amour !</div>
            <div className="hero-names">{couple.nom1}<span className="hero-and">&amp;</span>{couple.nom2}</div>
            <div className="hero-date">9 &amp; 11 · Juillet · 2026</div>
          </div>
        </div>

        {/* COUNTDOWN */}
        <div className="cd">
          {[["days","Jours"],["hours","Heures"],["mins","Min"],["secs","Sec"]].map(([k,l],i)=>(
            <div key={k} style={{display:"flex",alignItems:"center"}}>
              {i>0 && <span className="cd-s" style={{marginRight:8}}>·</span>}
              <div className="cd-u"><div className="cd-n">{String(countdown[k]??0).padStart(2,"0")}</div><div className="cd-l">{l}</div></div>
            </div>
          ))}
        </div>

        {/* TABS */}
        <div className="tabs">
          {NAV.map(n=><button key={n.id} className={`tab${tab===n.id?" active":""}`} onClick={()=>setTab(n.id)}>{n.icon} {n.label}</button>)}
        </div>

        {/* ACCUEIL */}
        {tab==="accueil" && (
          <div className="sec">
            <div className="invite-card">
              <div style={{fontSize:10,letterSpacing:4,textTransform:"uppercase",color:"#d4a96a",marginBottom:10}}>Faire-part de mariage</div>
              <div style={{fontFamily:"'Playfair Display',serif",fontSize:13,color:"#f5d9a8",lineHeight:1.8,fontStyle:"italic"}}>{couple.histoire}</div>
              <div style={{display:"flex",gap:12,marginTop:16}}>
                <div className="date-box"><div className="date-day">{new Date(couple.date1).getDate()}</div><div className="date-month">Juil {new Date(couple.date1).getFullYear()}</div><div className="date-event">{couple.label1}</div></div>
                <div className="date-box"><div className="date-day">{new Date(couple.date2).getDate()}</div><div className="date-month">Juil {new Date(couple.date2).getFullYear()}</div><div className="date-event">{couple.label2}</div></div>
              </div>
            </div>
            <div style={{padding:"0 16px 4px"}}><div className="st" style={{marginBottom:0}}>Notre histoire</div><div className="ss">En images</div></div>
            <div className="slider">
              {PHOTOS_COUPLE.map(p=>(
                <div className="slide" key={p.id}>
                  <img src={p.src} alt={p.label}/>
                  <div className="slide-info"><div style={{fontFamily:"'Playfair Display',serif",fontSize:14,color:"#2a1a0a"}}>{p.label}</div><div style={{fontSize:11,color:"#8B6035"}}>{p.author}</div></div>
                </div>
              ))}
              {photos.slice(-3).map(p=>(
                <div className="slide" key={p.id}>
                  <img src={p.url} alt={p.label} style={{width:"100%",height:270,objectFit:"cover",display:"block"}}/>
                  <div className="slide-info"><div style={{fontFamily:"'Playfair Display',serif",fontSize:14,color:"#2a1a0a"}}>{p.label||"Photo"}</div><div style={{fontSize:11,color:"#8B6035"}}>par {p.author}</div></div>
                </div>
              ))}
            </div>
          </div>
        )}

        {/* PROGRAMME */}
        {tab==="programme" && (
          <div className="sec">
            <div className="st">Programme</div><div className="ss">Le déroulé des festivités</div>
            {Object.entries(grouped).map(([date,items])=>(
              <div key={date} style={{marginBottom:20}}>
                <span style={{fontSize:10,letterSpacing:3,textTransform:"uppercase",color:"#8B4513",marginBottom:10,fontWeight:600,background:"#fceee0",padding:"6px 12px",borderRadius:20,display:"inline-block"}}>{date}</span>
                {items.map((p,i)=>(
                  <div className="prog-item" key={i}>
                    <div style={{fontSize:12,fontWeight:600,color:"#8B4513",minWidth:42,paddingTop:2}}>{p.time}</div>
                    <div style={{fontSize:26,flexShrink:0}}>{p.icon}</div>
                    <div style={{flex:1}}>
                      <div style={{fontFamily:"'Playfair Display',serif",fontSize:16,color:"#2a1a0a"}}>{p.title}</div>
                      <div style={{fontSize:12,color:"#7a6050",marginTop:2}}>{p.desc}</div>
                      <div style={{fontSize:10,color:"#c8860a",marginTop:4}}>Durée : {p.duration}</div>
                    </div>
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}

        {/* INFOS */}
        {tab==="infos" && (
          <div className="sec">
            <div className="st">Informations</div><div className="ss">Tout ce qu'il faut savoir</div>
            {infos.map((info,i)=>(
              <div className="info-card" key={i} style={{background:info.color}}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:8}}><span style={{fontSize:22}}>{info.icon}</span><span style={{fontFamily:"'Playfair Display',serif",fontSize:17,color:"#2a1a0a"}}>{info.title}</span></div>
                <div style={{fontSize:13,color:"#5a4030",lineHeight:1.7,whiteSpace:"pre-line"}}>{info.content}</div>
              </div>
            ))}
          </div>
        )}

        {/* RSVP */}
        {tab==="rsvp" && (
          <div className="sec">
            <div className="st">RSVP</div><div className="ss">Confirmez votre présence</div>
            <div className="rsvp-stats">
              <div className="stat-box" style={{background:"#e6f4ea"}}><div className="stat-num" style={{color:"#2d8a4e"}}>{presentCount}</div><div style={{fontSize:10,letterSpacing:1,textTransform:"uppercase",color:"#7a6050",marginTop:2}}>Présents</div></div>
              <div className="stat-box" style={{background:"#fde8e8"}}><div className="stat-num" style={{color:"#c0392b"}}>{absentCount}</div><div style={{fontSize:10,letterSpacing:1,textTransform:"uppercase",color:"#7a6050",marginTop:2}}>Absents</div></div>
              <div className="stat-box" style={{background:"#fdf3e8"}}><div className="stat-num" style={{color:"#8B4513"}}>{rsvps.length}</div><div style={{fontSize:10,letterSpacing:1,textTransform:"uppercase",color:"#7a6050",marginTop:2}}>Réponses</div></div>
            </div>

            {rsvpStep==="form" ? (
              <div className="card">
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:20,color:"#2a1a0a",marginBottom:16}}>Votre réponse</div>
                <div style={{display:"flex",gap:10,marginBottom:18}}>
                  <button onClick={()=>setRsvpChoice("yes")} style={{flex:1,padding:"13px",borderRadius:12,border:`2px solid ${rsvpChoice==="yes"?"#2d8a4e":"#e0d4c8"}`,background:rsvpChoice==="yes"?"#e6f4ea":"white",color:rsvpChoice==="yes"?"#2d8a4e":"#7a6050",fontFamily:"'Nunito',sans-serif",fontSize:14,cursor:"pointer",fontWeight:700}}>✓ Je serai là !</button>
                  <button onClick={()=>setRsvpChoice("no")} style={{flex:1,padding:"13px",borderRadius:12,border:`2px solid ${rsvpChoice==="no"?"#c0392b":"#e0d4c8"}`,background:rsvpChoice==="no"?"#fde8e8":"white",color:rsvpChoice==="no"?"#c0392b":"#7a6050",fontFamily:"'Nunito',sans-serif",fontSize:14,cursor:"pointer",fontWeight:700}}>✗ Absent(e)</button>
                </div>
                {rsvpChoice && (
                  <div style={{animation:"fu 0.3s ease"}}>
                    <div style={{fontSize:13,color:"#8B6035",marginBottom:14,fontStyle:"italic"}}>{rsvpChoice==="yes"?"Super ! Dites-nous qui vous êtes 😊":"Dommage... Dites-nous quand même qui vous êtes 💕"}</div>
                    <div style={{display:"flex",gap:10,marginBottom:14}}>
                      <div style={{flex:1}}>
                        <div style={{fontSize:10,letterSpacing:1.5,textTransform:"uppercase",color:"#8B6035",fontWeight:700,marginBottom:5}}>Prénom *</div>
                        <input className="inp" placeholder="Marie" value={rsvpPrenom} onChange={e=>setRsvpPrenom(e.target.value)} />
                      </div>
                      <div style={{flex:1}}>
                        <div style={{fontSize:10,letterSpacing:1.5,textTransform:"uppercase",color:"#8B6035",fontWeight:700,marginBottom:5}}>Nom *</div>
                        <input className="inp" placeholder="Nzamba" value={rsvpNom} onChange={e=>setRsvpNom(e.target.value)} />
                      </div>
                    </div>
                    <button className="btn-main" onClick={submitRsvp} disabled={!rsvpPrenom.trim()||!rsvpNom.trim()}>Confirmer ma réponse →</button>
                  </div>
                )}
              </div>
            ) : (
              <div className="card" style={{textAlign:"center",padding:"24px 18px"}}>
                <div style={{fontSize:40,marginBottom:12}}>{rsvpChoice==="yes"?"🎉":"💕"}</div>
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:20,color:"#2a1a0a",marginBottom:8}}>{rsvpChoice==="yes"?"À bientôt !":"Vous nous manquerez !"}</div>
                <div style={{fontSize:13,color:"#8B6035"}}>{rsvpPrenom} {rsvpNom} — réponse enregistrée ✓</div>
                <button onClick={()=>{setRsvpStep("form");setRsvpChoice(null);setRsvpPrenom("");setRsvpNom("");}} style={{marginTop:16,background:"none",border:"1.5px solid #e8dcd0",borderRadius:10,padding:"8px 16px",color:"#8B6035",cursor:"pointer",fontSize:12,fontFamily:"'Nunito',sans-serif"}}>Modifier ma réponse</button>
              </div>
            )}

            {rsvps.length>0 && (
              <div className="card" style={{marginTop:4}}>
                <div style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:"#2a1a0a",marginBottom:14}}>Qui a répondu</div>
                {rsvps.slice().reverse().map(r=>(
                  <div className="guest-row" key={r.id}>
                    <div className="guest-av">{r.prenom[0]}</div>
                    <div style={{flex:1}}><div style={{fontSize:13,fontWeight:600}}>{r.fullName}</div><div style={{fontSize:11,color:"#b09070"}}>{r.time}</div></div>
                    <span className={`bdg ${r.present?"bdg-y":"bdg-n"}`}>{r.present?"Présent(e)":"Absent(e)"}</span>
                  </div>
                ))}
              </div>
            )}
          </div>
        )}

        {/* PHOTOS */}
        {tab==="photos" && (
          <div className="sec">
            <div className="st">Galerie</div><div className="ss">Partagez vos photos du mariage</div>
            <div className={`upload-zone${drag?" drag":""}`}
              onDragOver={e=>{e.preventDefault();setDrag(true);}}
              onDragLeave={()=>setDrag(false)}
              onDrop={e=>{e.preventDefault();setDrag(false);handleFile(e.dataTransfer.files[0]);}}
              onClick={()=>fileRef.current?.click()}>
              <input ref={fileRef} type="file" accept="image/*" capture="environment" onChange={e=>handleFile(e.target.files[0])} />
              <div style={{fontSize:40,marginBottom:10}}>📷</div>
              <div style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:"#2a1a0a",marginBottom:4}}>Ajouter une photo</div>
              <div style={{fontSize:12,color:"#8B6035"}}>Appuyez pour prendre ou choisir une photo</div>
            </div>

            {photos.length===0 && <div style={{textAlign:"center",padding:"20px 0",color:"#b09070",fontSize:13,fontStyle:"italic"}}>Soyez le premier à partager une photo ! 📸</div>}

            {photos.length>0 && (
              <>
                <div style={{fontSize:11,letterSpacing:2,textTransform:"uppercase",color:"#8B4513",marginBottom:10,fontWeight:600}}>📸 Photos des invités ({photos.length})</div>
                <div className="photo-grid">
                  {photos.slice().reverse().map(p=>(
                    <div className="photo-card" key={p.id}>
                      <img src={p.url} alt={p.label}/>
                      <div className="photo-info">
                        <div style={{fontFamily:"'Playfair Display',serif",fontSize:12,color:"#2a1a0a"}}>{p.label||"Photo"}</div>
                        <div style={{fontSize:10,color:"#8B6035"}}>par {p.author} · {p.time}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </>
            )}
          </div>
        )}

        {/* LIVRE D'OR */}
        {tab==="or" && (
          <div className="sec">
            <div className="st">Livre d'or</div><div className="ss">Laissez un message aux mariés</div>
            <div className="card">
              <div style={{fontFamily:"'Playfair Display',serif",fontSize:18,color:"#2a1a0a",marginBottom:14}}>Votre message</div>
              <div style={{display:"flex",gap:10,marginBottom:10}}>
                <input className="inp" placeholder="Prénom" value={newMsgPrenom} onChange={e=>setNewMsgPrenom(e.target.value)} style={{flex:1}} />
                <input className="inp" placeholder="Nom" value={newMsgNom} onChange={e=>setNewMsgNom(e.target.value)} style={{flex:1}} />
              </div>
              <textarea className="inp" rows={3} placeholder="Écrivez vos vœux..." value={newMsg} onChange={e=>setNewMsg(e.target.value)} style={{marginBottom:10,resize:"none"}}/>
              <button className="btn-main" onClick={sendMessage} disabled={!newMsg.trim()||!newMsgPrenom.trim()||!newMsgNom.trim()}>Envoyer 💌</button>
              <div style={{fontSize:11,color:"#b09070",textAlign:"center",marginTop:8}}>Visible après approbation des mariés</div>
            </div>
            {messages.filter(m=>m.approved).length===0 && <div style={{textAlign:"center",padding:20,color:"#b09070",fontSize:13,fontStyle:"italic"}}>Soyez le premier à laisser un message ! 💕</div>}
            {messages.filter(m=>m.approved).slice().reverse().map(m=>(
              <div className="msg-card" key={m.id}>
                <div style={{fontSize:13,color:"#4a3020",lineHeight:1.6,fontStyle:"italic"}}>"{m.msg}"</div>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginTop:8}}>
                  <div style={{fontFamily:"'Playfair Display',serif",fontSize:15,fontWeight:700,color:"#8B4513"}}>{m.name}</div>
                  <div style={{fontSize:10,color:"#b09070"}}>{m.time}</div>
                </div>
              </div>
            ))}
          </div>
        )}

        {/* MENU */}
        {tab==="menu" && (
          <div className="sec">
            <div className="st">Menu</div><div className="ss">Choisissez votre repas</div>
            {menus.map(m=>(
              <div className={`menu-item${selectedMeal===m.id?" sel":""}`} key={m.id} onClick={()=>setSelectedMeal(m.id)}>
                <div style={{fontSize:28}}>{m.icon}</div>
                <div style={{flex:1}}><div style={{fontSize:14,color:"#2a1a0a",fontWeight:600}}>{m.name}</div><div style={{fontSize:12,color:"#8B6035",marginTop:2}}>{m.desc}</div></div>
                <div className="menu-check">{selectedMeal===m.id?"✓":""}</div>
              </div>
            ))}
            {selectedMeal && <button className="btn-main" style={{marginTop:14}}>Confirmer mon choix ✓</button>}
          </div>
        )}

        {/* TABLE */}
        {tab==="table" && (
          <div className="sec">
            <div className="st">Plan de table</div><div className="ss">Retrouvez votre place</div>
            {tables.map((t,i)=>(
              <div style={{background:"white",borderRadius:14,padding:14,marginBottom:10,boxShadow:"0 2px 10px rgba(139,69,19,0.07)"}} key={t.id}>
                <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:12}}>
                  <div style={{width:32,height:32,borderRadius:"50%",background:"linear-gradient(135deg,#8B4513,#c8860a)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Playfair Display',serif",fontSize:15,fontWeight:700,color:"white",flexShrink:0}}>{i+1}</div>
                  <div style={{fontFamily:"'Playfair Display',serif",fontSize:17,color:"#2a1a0a"}}>{t.name}</div>
                </div>
                {t.guests.map((g,j)=>(
                  <div key={j} style={{display:"flex",alignItems:"center",gap:8,padding:"6px 0",borderBottom:"1px solid #f5ece0",fontSize:13,color:"#4a3020"}}>
                    <div style={{width:6,height:6,borderRadius:"50%",background:"#c8860a",flexShrink:0}}/>{g}
                  </div>
                ))}
              </div>
            ))}
          </div>
        )}

        <div className="bnav">
          {NAV.map(n=>(
            <button key={n.id} className={`nb${tab===n.id?" active":""}`} onClick={()=>setTab(n.id)}>
              <span className="nb-icon">{n.icon}</span>
              <span className="nb-label">{n.label}</span>
            </button>
          ))}
        </div>
      </div>
      {toast && <div className="toast">{toast}</div>}
    </>
  );
}
